import { config } from 'dotenv';
config\({ path: '.env' }\);
import knex from 'knex';

const db = knex\({
  client: 'pg',
  connection: process.env.SUPABASE_CONNECTION_URL
}\);

async function main\(\) {
  const rows = await db\('page_layers'\)
    .where\('page_id', 'ffcedc86-ecf9-44c4-9c02-05a0e065fcb5'\)
    .where\('is_published', false\)
    .orderBy\('created_at', 'desc'\)
    .limit\(1\);

  if \(!rows.length\) {
    console.log\('No draft layers found'\);
    await db.destroy\(\);
    return;
  }

  const layers = rows[0].layers;

  function findLayer\(layers, id\) {
    for \(const l of layers\) {
      if \(l.id === id\) return l;
      if \(l.children\) {
        const found = findLayer\(l.children, id\);
        if \(found\) return found;
      }
    }
    return null;
  }

  const target = findLayer\(layers, 'lyr-mmkit4jiln3dzz'\);
  if \(target\) {
    console.log\('FOUND LAYER:'\);
    console.log\(JSON.stringify\(target, null, 2\).substring\(0, 3000\)\);
  } else {
    console.log\('Layer lyr-mmkit4jiln3dzz not found.'\);
    console.log\('Top-level layers:'\);
    for \(const l of layers\) {
      console.log\(' -', l.id, '|', l.name, '|', l.customName || '\(no name\)'\);
      if \(l.children\) {
        for \(const c of l.children\) {
          console.log\('   -', c.id, '|', c.name, '|', c.customName || '\(no name\)'\);
        }
      }
    }
  }
  await db.destroy\(\);
}
main\(\).catch\(e => { console.error\(e.message\); process.exit\(1\); }\);
